1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / processing fee ---
6	  it("empty item list returns premium 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums per item ---
15	  it("single plain sword returns premium 105 G (100 base + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 105 }] });
21	  });
22	  it("single plain amulet returns premium 65 G (60 base + 5 fee)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 65 }] });
28	  });
29	  it("single plain staff returns premium 85 G (80 base + 5 fee)", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 85 }] });
35	  });
36	  it("single plain potion returns premium 45 G (40 base + 5 fee)", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 45 }] });
42	  });
43	
44	  // --- Components ---
45	  it("single rune returns premium 30 G (25 base + 5 fee)", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 30 }] });
51	  });
52	  it.todo("2 runes returns premium 55 G (50 base + 5 fee)");
53	  it.todo("3 runes returns premium 65 G (block: 60 base + 5 fee)");
54	  it.todo("4 runes returns premium 105 G (no block: 100 base + 5 fee)");
55	  it.todo("7 runes returns premium 180 G (175 base + 5 fee)");
56	
57	  // --- 'Alike' clarification (❓) ---
58	  it.todo("2 runes + 1 moonstone returns premium 80 G (75 base + 5 fee — different types, no block)");
59	  it.todo("3 runes + 3 moonstones returns premium 125 G (120 base + 5 fee — two separate blocks)");
60	
61	  // --- Cursed surcharge ---
62	  it.todo("single cursed sword (newcomer) returns 165 G (100 base + 50 curse + 10 first + 5 fee)");
63	
64	  // --- High enchantment threshold ---
65	  it.todo("sword with enchantment 5 (newcomer) adds 30% high-enchantment surcharge → 145 G (100 + 30 + 10 + 5)");
66	  it.todo("sword with enchantment 4 (newcomer) does not add high-enchantment surcharge → 115 G (100 + 10 + 5)");
67	
68	  // --- Modifier scope on multi-item policies (❓) ---
69	  it.todo("policy with cursed sword + plain amulet (newcomer) → 231 G (160 base + 50 curse + 16 first + 5 fee)");
70	
71	  // --- Loyalty (≥ 2 years) ---
72	  it.todo("plain sword for 2-year customer → loyalty applies; first contract → 95 G (100 − 20 + 10 + 5)");
73	
74	  // --- Follow-up contract ---
75	  it.todo("second quote for newcomer (0 years) of plain sword → follow-up discount applies → 100 G (100 − 15 + 10 + 5)");
76	
77	  // --- Rounding in MHPCO favor (premium rounds up) ---
78	  it.todo("premium calculation yielding 197.5 G rounds up to 198 G");
79	
80	  // --- Integration: long-standing 2nd contract ---
81	  it.todo("long-standing customer's 2nd contract with cursed sword enchantment 7 → 160 G");
82	
83	  // --- Claim: standard reimbursement ---
84	  it.todo("standard sword damage 500 G → payout 400 G (500 − 100 deductible)");
85	  it.todo("rune damage 200 G → payout 100 G (200 − 100 deductible; no special clause)");
86	
87	  // --- Claim: high enchantment ---
88	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
89	
90	  // --- Claim: dragon material ---
91	  it.todo("dragon sword enchantment 5, damage 800 G → payout 700 G (full then deductible)");
92	
93	  // --- Claim: both clauses (high enchantment wins) ---
94	  it.todo("dragon sword enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
95	  it.todo("dragon sword enchantment exactly 8, damage 1000 G → payout 400 G (high-enchantment clause applies)");
96	
97	  // --- Multiple damages: deductible per event ---
98	  it.todo("dragon attack on sword (500) and amulet (300) → payout 600 G (deductible per item)");
99	
100	  // --- Multiple same-type items ---
101	  it.todo("policy with two swords, both damaged → each gets own deductible");
102	  it.todo("damages array has more items of a type than policy covers → CLI exits non-zero (claim rejected)");
103	
104	  // --- Cap ---
105	  it.todo("sword (cap 2000) with two 1500 G claims → first payout 1400, remaining 600; second payout 600, remaining 0");
106	  it.todo("cursed sword cap based on unmodified insurance value → 2000 G");
107	
108	  // --- Rounding payout (rounds down) ---
109	  it.todo("payout calculation yielding 350.5 G rounds down to 350 G");
110	
111	  // --- Edge cases ---
112	  it.todo("quote with unknown item type → CLI exits non-zero; error to stderr");
113	  it.todo("claim references item not in policy → CLI exits non-zero");
114	  it.todo("claim damage with negative amount → CLI exits non-zero");
115	});
