1	const PROCESSING_FEE = 5;
2	
3	const BASE_PRICE_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
14	
15	const itemBasePrice = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
16	
17	const quotePremium = (step: Step): number =>
18	  step.items.reduce((sum, item) => sum + itemBasePrice(item), 0) + PROCESSING_FEE;
19	
20	export const runScenario = (input: unknown): unknown => ({
21	  results: (input as Scenario).steps.map((step) => ({
22	    premium: quotePremium(step),
23	  })),
24	});
